import{_ as t,o as a,c as r,a2 as i}from"./chunks/framework.D6hBiDio.js";const p=JSON.parse('{"title":"Introduction","description":"What is this project, why use it, and what do you need before starting","frontmatter":{"title":"Introduction","description":"What is this project, why use it, and what do you need before starting"},"headers":[],"relativePath":"en/guide/introduction.md","filePath":"en/guide/introduction.md","lastUpdated":1784575673000}'),o={name:"en/guide/introduction.md"};function s(l,e,n,d,c,h){return a(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>New to this project? Start here. This page explains what the project does and what you need before installing.</p><h2 id="what-is-this-project" tabindex="-1">What Is This Project? <a class="header-anchor" href="#what-is-this-project" aria-label="Permalink to &quot;What Is This Project?&quot;">​</a></h2><p>This is a community-maintained feed that provides <strong>smaller Tailscale packages</strong> for OpenWrt routers and devices.</p><p><a href="https://tailscale.com/" target="_blank" rel="noreferrer">Tailscale</a> is a zero-config VPN that lets you securely connect your devices into a private network (a &quot;tailnet&quot;). It is built on WireGuard and works through NAT and firewalls without port forwarding.</p><p>The official OpenWrt Tailscale package can be large. This project rebuilds the <strong>exact same Tailscale source code</strong> with size optimizations:</p><ul><li>Merges <code>tailscale</code> + <code>tailscaled</code> into a single binary</li><li>Strips optional features (AWS, Kubernetes, Taildrop, etc.) via build tags</li><li>Applies <a href="https://upx.github.io/" target="_blank" rel="noreferrer">UPX</a> compression (<code>--best --lzma</code>)</li></ul><p><strong>Result:</strong> 30–60% smaller binary, same functionality. Ideal for routers with limited flash storage.</p><div class="tip custom-block"><p class="custom-block-title">No Functional Changes</p><p>The source code is taken directly from the <a href="https://github.com/tailscale/tailscale" target="_blank" rel="noreferrer">official Tailscale repository</a> with no modifications. Only compiler flags and UPX compression are added. See the <a href="/openwrt-tailscale/en/reference/security.html">Security Statement</a> for details.</p></div><h2 id="is-this-safe-to-use" tabindex="-1">Is This Safe to Use? <a class="header-anchor" href="#is-this-safe-to-use" aria-label="Permalink to &quot;Is This Safe to Use?&quot;">​</a></h2><p>Yes. The entire build process is:</p><ul><li><strong>Open-source</strong> — all scripts and workflows are public on GitHub</li><li><strong>Automated</strong> — packages are built by GitHub Actions, no manual uploads</li><li><strong>Auditable</strong> — every build log is publicly available</li><li><strong>Reproducible</strong> — you can build the packages yourself using the <a href="/openwrt-tailscale/en/build/">Build Guide</a></li></ul><p>See the <a href="/openwrt-tailscale/en/reference/security.html">Security Statement</a> for full details.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>Before installing, make sure your device meets these requirements:</p><table tabindex="0"><thead><tr><th>Requirement</th><th>Minimum</th><th>Notes</th></tr></thead><tbody><tr><td>OpenWrt version</td><td>22.03 or later</td><td>21.02 is not supported</td></tr><tr><td>Storage space</td><td>&lt; 8 MB free</td><td>UPX-compressed binary is small</td></tr><tr><td>RAM</td><td>256 MB recommended</td><td>Devices with less RAM may need <a href="/openwrt-tailscale/en/guide/oom.html">memory optimization</a></td></tr><tr><td>Kernel modules</td><td><code>kmod-tun</code>, <code>ca-bundle</code></td><td>Usually pre-installed</td></tr><tr><td>Network</td><td>Access to GitHub or a mirror</td><td>Needed to download packages</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">Low-RAM Devices</p><p>If your device has less than 256 MB RAM, Tailscale may be killed by the OOM Killer. See <a href="/openwrt-tailscale/en/guide/oom.html">Memory Optimization</a> for a fix that trades CPU for lower memory usage.</p></div><h2 id="package-types" tabindex="-1">Package Types <a class="header-anchor" href="#package-types" aria-label="Permalink to &quot;Package Types&quot;">​</a></h2><p>OpenWrt changed its package manager starting from version 25.12. You need to pick the right package type:</p><table tabindex="0"><thead><tr><th>OpenWrt Version</th><th>Package Manager</th><th>Package Type</th></tr></thead><tbody><tr><td>25.12 or later</td><td>APK</td><td><code>.apk</code></td></tr><tr><td>24.10 or earlier</td><td>OPKG</td><td><code>.ipk</code></td></tr></tbody></table><p>Not sure which version you have? The <a href="/openwrt-tailscale/en/guide/quick-start.html">Quick Start</a> guide shows you how to check.</p><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="/openwrt-tailscale/en/guide/quick-start.html">Quick Start</a> — Choose your installation method</li><li><a href="/openwrt-tailscale/en/reference/faq.html">FAQ</a> — Common questions answered</li><li><a href="/openwrt-tailscale/en/reference/architectures.html">Supported Architectures</a> — Check if your device is supported</li></ul>',23)])])}const m=t(o,[["render",s]]);export{p as __pageData,m as default};
